#!/usr/bin/env python3
"""
Script para criar um novo workflow na N8N via API

Uso:
    python workflow_create.py                           # Cria workflow_1, workflow_2, etc
    python workflow_create.py -r workflow_completo      # Cria com nome específico
"""

import argparse
import json
import os
import sys
from pathlib import Path

try:
    import requests
    from dotenv import load_dotenv
    load_dotenv()
except ImportError:
    print("Erro: Instale as bibliotecas necessarias:")
    print("  pip install requests python-dotenv")
    sys.exit(1)

# Configurar encoding para Windows
import io
if sys.platform == "win32":
    sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8', errors='ignore')
    sys.stderr = io.TextIOWrapper(sys.stderr.buffer, encoding='utf-8', errors='ignore')


def get_next_workflow_number(base_url: str, api_key: str) -> int:
    """Busca todos os workflows e retorna o próximo número sequencial"""

    base_url = base_url.rstrip('/')
    url = f"{base_url}/api/v1/workflows"

    headers = {
        "accept": "application/json",
        "X-N8N-API-KEY": api_key
    }

    try:
        response = requests.get(url, headers=headers, timeout=30)

        if response.status_code != 200:
            return 1

        workflows = response.json()
        data = workflows.get("data", [])

        # Encontrar o maior número workflow_N existente
        max_number = 0
        for wf in data:
            name = wf.get("name", "")
            if name.startswith("workflow_"):
                try:
                    number = int(name.replace("workflow_", ""))
                    if number > max_number:
                        max_number = number
                except ValueError:
                    continue

        return max_number + 1

    except Exception as e:
        print(f"Aviso: Não foi possível buscar workflows existentes: {e}")
        return 1


def create_workflow(workflow_name: str, base_url: str, api_key: str, silent: bool = False) -> bool:
    """Cria um novo workflow na N8N"""

    base_url = base_url.rstrip('/')
    url = f"{base_url}/api/v1/workflows"

    headers = {
        "accept": "application/json",
        "Content-Type": "application/json",
        "X-N8N-API-KEY": api_key
    }

    # Workflow mínimo para criação (apenas campos necessários)
    workflow_data = {
        "name": workflow_name,
        "nodes": [],
        "connections": {},
        "settings": {}
    }

    if not silent:
        print(f"Criando workflow: {workflow_name}")
        print(f"URL: {url}")

    try:
        response = requests.post(url, json=workflow_data, headers=headers, timeout=30)

        if response.status_code == 401:
            if not silent:
                print("Erro 401: API KEY inválida ou expirada")
            return False
        elif response.status_code == 201 or response.status_code == 200:
            result = response.json()
            if not silent:
                print(f"\n✓ Workflow criado com sucesso!")
                print(f"  ID: {result.get('id')}")
                print(f"  Nome: {result.get('name')}")
                print(f"  Ativo: {result.get('active', False)}")
            else:
                print(result.get('name'))
            return True
        else:
            if not silent:
                print(f"Erro {response.status_code}: {response.text}")
            return False

    except requests.exceptions.Timeout:
        if not silent:
            print("Erro: Timeout na requisição")
        return False
    except requests.exceptions.ConnectionError:
        if not silent:
            print(f"Erro: Não foi possível conectar em {base_url}")
        return False
    except Exception as e:
        if not silent:
            print(f"Erro inesperado: {e}")
        return False


def new_workflow_date():
    from datetime import datetime, timezone
    return datetime.now(timezone.utc).isoformat()


def new_workflow_date():
    from datetime import datetime
    return datetime.utcnow().isoformat() + "Z"


def main():
    parser = argparse.ArgumentParser(
        description="Cria novos workflows na N8N via API",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Exemplos:
  python workflow_create.py                      # Cria workflow_1, workflow_2, etc
  python workflow_create.py -r meus_agentes     # Cria com nome específico
  python workflow_create.py -r bot-inteligente  # Cria com nome específico
  python workflow_create.py --one               # Imprime apenas o nome do workflow
        """
    )

    parser.add_argument(
        "--rename", "-r",
        dest="custom_name",
        metavar="NOME",
        help="Nome personalizado para o workflow"
    )

    parser.add_argument(
        "--url", "-u",
        default=os.getenv("N8N_URL", "http://localhost:5678"),
        help="URL da instância N8N (padrão: N8N_URL env)"
    )

    parser.add_argument(
        "--key", "-k",
        default=os.getenv("N8N_API_KEY"),
        help="API Key da N8N (padrão: N8N_API_KEY env)"
    )

    parser.add_argument(
        "--one",
        action="store_true",
        help="Imprime apenas o nome do arquivo gerado"
    )

    args = parser.parse_args()

    if not args.key:
        print("Erro: API KEY não fornecida")
        print("Use --key SUA_KEY ou defina N8N_API_KEY")
        sys.exit(1)

    # Determinar o nome do workflow
    if args.custom_name:
        workflow_name = args.custom_name
    else:
        # Buscar próximo número sequencial
        next_number = get_next_workflow_number(args.url, args.key)
        workflow_name = f"workflow_{next_number}"

    success = create_workflow(
        workflow_name=workflow_name,
        base_url=args.url,
        api_key=args.key,
        silent=args.one
    )

    sys.exit(0 if success else 1)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""
Script de Parâmetros N8N por Fórmula

Este script lê workflows N8N com nodes pré-criados
e aplica configurações de parâmetros baseadas em fórmulas de texto simples.

Uso:
    python parameters.py workflow.json "agent.temperature=0.7"
    python parameters.py workflow.json workflow.params
    python parameters.py workflow.json "http.url=https://api.example.com" --output custom.json
"""

import json
import sys
import re
import argparse
from typing import Dict, List, Tuple, Optional, Any, Union
from pathlib import Path


class ParametersCreate:
    """Classe principal para configurar parâmetros de workflows N8N."""

    def __init__(self, workflow_path: str):
        self.workflow_path = workflow_path
        self.workflow = self._carregar_workflow()
        self.nodes_por_nome = {n['name']: n for n in self.workflow['nodes']}

    def _carregar_workflow(self) -> dict:
        """Carrega o workflow JSON do arquivo."""
        with open(self.workflow_path, 'r', encoding='utf-8') as f:
            return json.load(f)

    def _split_preserve_quotes(self, text: str, delimiter: str) -> List[str]:
        """Split preservando aspas."""
        parts = []
        current = []
        in_quotes = False
        quote_char = None

        for char in text:
            if char in '"\'':
                if not in_quotes:
                    in_quotes = True
                    quote_char = char
                elif char == quote_char:
                    in_quotes = False
                current.append(char)
            elif char == delimiter and not in_quotes:
                parts.append(''.join(current))
                current = []
            else:
                current.append(char)

        if current:
            parts.append(''.join(current))

        return parts

    def _parse_formula(self, formula: str) -> List[dict]:
        """
        Parse fórmula em lista de atribuições de parâmetros.

        Sintaxe suportada:
        - node.field=value           - Campo simples
        - node.field.subfield=value  - Campo aninhado
        - node.field={...}           - Objeto JSON
        - node.field=[...]           - Array JSON
        - node.array[0].field=value  - Item específico de array
        - node.field=value1;node2.field=value2  - Múltiplos comandos

        Modificadores:
        - +node.field=value          - Adiciona ao array/objeto existente
        - -node.field                - Remove campo
        - !node.field=value          - Força sobrescrever

        Args:
            formula: String da fórmula

        Returns:
            Lista de dicionários de atribuição
        """
        atribuicoes = []

        # Divide por ; para comandos múltiplos
        comandos = self._split_preserve_quotes(formula, ';')

        for cmd in comandos:
            cmd = cmd.strip()
            if not cmd or cmd.startswith('#'):
                continue

            atribuicao = self._parse_assignment(cmd)
            if atribuicao:
                atribuicoes.append(atribuicao)

        return atribuicoes

    def _parse_assignment(self, cmd: str) -> Optional[dict]:
        """
        Parse uma única atribuição.

        Returns:
            Dict com: node, path, value, modifier
        """
        modifier = None
        original_cmd = cmd

        # Detecta modificador
        if cmd.startswith('+'):
            modifier = 'add'
            cmd = cmd[1:].lstrip()
        elif cmd.startswith('-'):
            modifier = 'remove'
            cmd = cmd[1:].lstrip()
        elif cmd.startswith('!'):
            modifier = 'force'
            cmd = cmd[1:].lstrip()

        if modifier == 'remove':
            # Para remoção, o valor é o caminho inteiro
            # Ex: -node.field.subfield
            parts = cmd.split('=', 1)
            path = parts[0].strip()
            return {
                'node': self._extract_node_name(path),
                'path': self._extract_field_path(path),
                'value': None,
                'modifier': modifier
            }

        # Encontra o primeiro '=' que não está dentro de colchetes
        eq_pos = self._find_equals_outside_brackets(cmd)

        if eq_pos == -1:
            return None

        path = cmd[:eq_pos].strip()
        value_str = cmd[eq_pos + 1:].strip()

        return {
            'node': self._extract_node_name(path),
            'path': self._extract_field_path(path),
            'value': self._parse_value(value_str),
            'modifier': modifier
        }

    def _find_equals_outside_brackets(self, text: str) -> int:
        """Encontra o primeiro '=' que não está dentro de {} ou []."""
        bracket_depth = 0
        in_quotes = False
        quote_char = None

        for i, char in enumerate(text):
            if char in '"\'':
                if not in_quotes:
                    in_quotes = True
                    quote_char = char
                elif char == quote_char:
                    in_quotes = False
            elif char in '{[' and not in_quotes:
                bracket_depth += 1
            elif char in '}]' and not in_quotes:
                bracket_depth -= 1
            elif char == '=' and bracket_depth == 0 and not in_quotes:
                return i

        return -1

    def _extract_node_name(self, path: str) -> str:
        """Extrai o nome do node do caminho."""
        # Remove índices de array como [0]
        path = re.sub(r'\[\d+\]', '', path)
        # Usa : como separador principal (permite espaços no nome do node)
        # Fallback para . para compatibilidade
        if ':' in path:
            return path.split(':', 1)[0]
        return path.split('.', 1)[0]

    def _extract_field_path(self, path: str) -> str:
        """Extrai o caminho do campo (sem o nome do node)."""
        # Usa : como separador principal (permite espaços no nome do node)
        if ':' in path:
            parts = path.split(':', 1)
        else:
            parts = path.split('.', 1)

        if len(parts) > 1:
            # Preserva índices de array
            result = parts[1]
        else:
            result = ''

        # Processa índices de array
        # Transforma "field[0].subfield" em ["field", 0, "subfield"]
        return self._parse_path_with_indices(result)

    def _parse_path_with_indices(self, path: str) -> List[Union[str, int]]:
        """
        Converte caminho com índices para lista de componentes.

        Ex: "options.timeout" -> ["options", "timeout"]
        Ex: "queryParameters[0].name" -> ["queryParameters", 0, "name"]
        Ex: "array[0]" -> ["array", 0]
        """
        if not path:
            return []

        components = []
        current = []

        i = 0
        while i < len(path):
            char = path[i]

            if char == '.':
                if current:
                    components.append(''.join(current))
                    current = []
                i += 1
            elif char == '[':
                # Adiciona o componente atual
                if current:
                    components.append(''.join(current))
                    current = []

                # Encontra o fechamento ]
                j = path.find(']', i)
                if j != -1:
                    # Extrai o índice
                    index_str = path[i + 1:j].strip()
                    try:
                        components.append(int(index_str))
                    except ValueError:
                        # Mantém como string se não for número
                        components.append(index_str)
                    i = j + 1
                else:
                    # [ sem fechamento, trata como caractere normal
                    current.append(char)
                    i += 1
            else:
                current.append(char)
                i += 1

        # Adiciona o último componente
        if current:
            components.append(''.join(current))

        return components

    def _parse_value(self, value_str: str) -> Any:
        """
        Parse valor string para tipo Python apropriado.

        Suporta:
        - JSON objects/arrays: {...}, [...]
        - Boolean: true, false
        - Number: int, float
        - String: com ou sem aspas
        - Expressões N8N: {{ ... }}
        """
        value_str = value_str.strip()

        if not value_str:
            return None

        # JSON object ou array
        if value_str.startswith('{') or value_str.startswith('['):
            try:
                return json.loads(value_str)
            except json.JSONDecodeError:
                return value_str

        # Boolean
        if value_str.lower() == 'true':
            return True
        if value_str.lower() == 'false':
            return False

        # Null
        if value_str.lower() == 'null' or value_str.lower() == 'none':
            return None

        # Number
        try:
            if '.' in value_str or 'e' in value_str.lower():
                return float(value_str)
            return int(value_str)
        except ValueError:
            pass

        # String com aspas
        if (value_str.startswith('"') and value_str.endswith('"')) or \
           (value_str.startswith("'") and value_str.endswith("'")):
            try:
                return json.loads(value_str)
            except json.JSONDecodeError:
                return value_str[1:-1]

        # Expressão N8N (começa com = ou contém {{)
        if value_str.startswith('=') or '{{' in value_str:
            # Preserva a expressão como string
            if value_str.startswith('='):
                return value_str[1:]  # Remove o =, mas mantém as {{}}
            return value_str

        # String sem aspas (remove aspas externas se existirem)
        return value_str

    def _set_nested_value(self, obj: dict, path: List[Union[str, int]], value: Any,
                         modifier: Optional[str] = None) -> bool:
        """
        Define valor em caminho aninhado.

        Args:
            obj: Objeto alvo (node['parameters'])
            path: Lista de componentes do caminho
            value: Valor a definir
            modifier: Modificador ('add', 'remove', 'force', None)

        Returns:
            True se sucesso, False se falha
        """
        if not path:
            return False

        current = obj

        # Navega até o penúltimo nível
        for i, key in enumerate(path[:-1]):
            if isinstance(key, int):
                # Índice de array
                if not isinstance(current, list):
                    return False
                if key >= len(current):
                    return False
                current = current[key]
            else:
                # Chave de objeto
                if key not in current:
                    # Cria estrutura intermediária se não existe
                    next_key = path[i + 1]
                    if isinstance(next_key, int):
                        current[key] = []
                    else:
                        current[key] = {}

                current = current[key]

                if current is None:
                    return False

        final_key = path[-1]

        # Aplica modificação
        if modifier == 'remove':
            if isinstance(final_key, int):
                if isinstance(current, list) and 0 <= final_key < len(current):
                    current.pop(final_key)
            elif isinstance(current, dict) and final_key in current:
                del current[final_key]
            return True

        elif modifier == 'add':
            # Adiciona ao array existente ou mescla em objeto
            if isinstance(final_key, int):
                # Índice específico de array
                if isinstance(current, list):
                    # Se o valor é uma lista, estende o array
                    if isinstance(value, list):
                        current.extend(value)
                    else:
                        current.append(value)
            elif isinstance(current, dict):
                if final_key in current:
                    # Mescla objetos
                    existing = current[final_key]
                    if isinstance(existing, dict) and isinstance(value, dict):
                        existing.update(value)
                        return True
                    elif isinstance(existing, list) and isinstance(value, list):
                        existing.extend(value)
                        return True

                # Define o valor normalmente
                current[final_key] = value
                return True
            return False

        else:
            # Define valor normalmente
            if isinstance(final_key, int):
                if not isinstance(current, list):
                    return False
                # Expande array se necessário
                while len(current) <= final_key:
                    current.append(None)
                current[final_key] = value
            else:
                current[final_key] = value
            return True

    def validar_parametros(self, formula: str) -> bool:
        """
        Valida se todos os nodes e campos da fórmula existem no workflow.

        Returns:
            True se todos os nodes e campos são válidos
        """
        atribuicoes = self._parse_formula(formula)

        if not atribuicoes:
            print("AVISO: Nenhuma atribuição válida encontrada na fórmula")
            return False

        nodes_no_workflow = set(self.nodes_por_nome.keys())
        nodes_faltando = set()
        campos_invalidos = []

        for attr in atribuicoes:
            node_name = attr['node']

            if node_name not in nodes_no_workflow:
                nodes_faltando.add(node_name)
                continue

            # Valida campos (basic check)
            node = self.nodes_por_nome[node_name]
            params = node.get('parameters', {})

            if attr['modifier'] != 'add':
                # Verifica se o caminho existe (para modificadores diferentes de 'add')
                if not self._path_exists(params, attr['path']):
                    campos_invalidos.append(f"{node_name}.{'.'.join(str(p) for p in attr['path'])}")

        if nodes_faltando:
            print(f"\nERRO: Nodes não encontrados no workflow:")
            for node in sorted(nodes_faltando):
                print(f"  - {node}")
            print(f"\nNodes disponíveis:")
            for node in sorted(nodes_no_workflow):
                print(f"  - {node}")
            return False

        if campos_invalidos:
            print(f"\nAVISO: Campos que não existem (serão criados):")
            for campo in campos_invalidos:
                print(f"  - {campo}")
            # Não é erro fatal - campos podem ser criados

        return True

    def _path_exists(self, obj: Any, path: List[Union[str, int]]) -> bool:
        """Verifica se um caminho existe no objeto."""
        if not path:
            return True

        current = obj
        for key in path[:-1]:
            if isinstance(key, int):
                if not isinstance(current, list) or key >= len(current):
                    return False
                current = current[key]
            else:
                if not isinstance(current, dict) or key not in current:
                    return False
                current = current[key]

        final_key = path[-1]
        if isinstance(final_key, int):
            return isinstance(current, list) and final_key < len(current)

        return isinstance(current, dict) and final_key in current

    def aplicar_parametros(self, formula: str, silent: bool = False) -> dict:
        """
        Aplica as atribuições da fórmula ao workflow.

        Args:
            formula: String da fórmula de parâmetros
            silent: Se True, não imprime mensagens

        Returns:
            Workflow atualizado
        """
        atribuicoes = self._parse_formula(formula)

        if not atribuicoes:
            if not silent:
                print("AVISO: Nenhuma atribuição válida encontrada na fórmula")
            return self.workflow

        if not silent:
            print(f"Processando {len(atribuicoes)} atribuições...")

        for attr in atribuicoes:
            node_name = attr['node']
            path = attr['path']
            value = attr['value']
            modifier = attr['modifier']

            if node_name not in self.nodes_por_nome:
                if not silent:
                    print(f"  AVISO: Node não encontrado: {node_name}")
                continue

            node = self.nodes_por_nome[node_name]

            # Inicializa parameters se não existe
            if 'parameters' not in node:
                node['parameters'] = {}

            params = node['parameters']

            # Aplica a atribuição
            if modifier == 'remove':
                success = self._set_nested_value(params, path, None, modifier='remove')
                if success and not silent:
                    path_str = '.'.join(str(p) for p in path)
                    print(f"  -{node_name}.{path_str}")
            else:
                success = self._set_nested_value(params, path, value, modifier=modifier)
                if success:
                    if not silent:
                        path_str = '.'.join(str(p) for p in path)
                        mod_str = f"{modifier} " if modifier else ""
                        value_preview = str(value)[:50]
                        if len(value_preview) >= 50:
                            value_preview += "..."
                        print(f"  {node_name}.{path_str} = {value_preview}")
                else:
                    if not silent:
                        path_str = '.'.join(str(p) for p in path)
                        print(f"  AVISO: Falha ao definir {node_name}.{path_str}")

        return self.workflow

    def salvar(self, output_path: Optional[str] = None, silent: bool = False,
               one_mode: bool = False) -> str:
        """
        Salva workflow atualizado.

        Args:
            output_path: Caminho de saída. Se None, usa sufixo _params
            silent: Se True, não imprime mensagens
            one_mode: Se True, imprime apenas o nome do arquivo

        Returns:
            Caminho do arquivo salvo
        """
        if output_path is None:
            base = Path(self.workflow_path)
            output_path = str(base.parent / f"{base.stem}_params{base.suffix}")

        with open(output_path, 'w', encoding='utf-8') as f:
            json.dump(self.workflow, f, indent=2, ensure_ascii=False)

        if one_mode:
            print(output_path)
        elif not silent:
            print(f"\nWorkflow salvo em: {output_path}")

        return output_path

    @staticmethod
    def ler_params(params_path: str) -> str:
        """
        Lê parâmetros de arquivo, removendo comentários e linhas vazias.

        Args:
            params_path: Caminho do arquivo .params

        Returns:
            String da fórmula
        """
        with open(params_path, 'r', encoding='utf-8') as f:
            linhas = f.readlines()

        partes = []
        for linha in linhas:
            linha_original = linha
            linha = linha.strip()

            # Remove comentários
            if '#' in linha:
                # Verifica se # está dentro de aspas
                in_quotes = False
                quote_char = None
                hash_pos = -1
                for i, char in enumerate(linha):
                    if char in '"\'':
                        if not in_quotes:
                            in_quotes = True
                            quote_char = char
                        elif char == quote_char:
                            in_quotes = False
                    elif char == '#' and not in_quotes:
                        hash_pos = i
                        break

                if hash_pos >= 0:
                    linha = linha[:hash_pos].strip()

            if linha:
                partes.append(linha)

        # Junta com ; se necessário
        return ';'.join(partes)


def print_usage():
    """Imprime instruções de uso."""
    print("Uso: python parameters.py <workflow.json> <formula ou arquivo> [opções]")
    print()
    print("Sintaxe da Fórmula:")
    print("  node:field=value              - Campo simples (RECOMENDADO)")
    print("  node:field.subfield=value     - Campo aninhado")
    print("  node:field={...}              - Objeto JSON")
    print("  node:field=[...]              - Array JSON")
    print("  node:array[0]:field=value     - Item específico de array")
    print("  node:field=value1;node2:field=value2  - Múltiplos comandos")
    print()
    print("Nota: Use : como separador entre node e campo (permite espaços no nome)")
    print("      Também é suportado . (ponto) como separador alternativo")
    print()
    print("Modificadores:")
    print("  +node:field=value             - Adiciona ao array/objeto existente")
    print("  -node:field                   - Remove campo")
    print("  !node:field=value             - Força sobrescrever")
    print()
    print("Tipos de Valor:")
    print("  String                         - node:url=https://api.example.com")
    print("  Number                         - agent:temperature=0.7")
    print("  Boolean                        - agent:hasMemory=true")
    print("  JSON Object                    - node:options={'timeout': 30000}")
    print("  JSON Array                     - node:params=[{'name': 'a'}]")
    print("  Expressão N8N                  - node:text={{ $now }}")
    print()
    print("Arquivo .params:")
    print("  # Comentários começam com #")
    print("  http:method=POST")
    print("  http:url=https://api.example.com")
    print("  http:headers={'Auth': 'Bearer xxx'}")
    print()
    print("Opções:")
    print("  --output <path>  - Especifica caminho de saída")
    print("  --validate       - Apenas valida, não aplica")
    print("  --one            - Imprime apenas o nome do arquivo gerado")
    print("  --help, -h       - Mostra esta ajuda")
    print()
    print("Exemplos:")
    print('  python parameters.py wf.json "agent:temperature=0.7"')
    print('  python parameters.py wf.json "http:method=POST;http:url=https://api.com"')
    print('  python parameters.py wf.json \'http:headers={"Auth": "Bearer xxx"}\'')
    print('  python parameters.py wf.json "AI Agent:text=Hello"  # nomes com espaço')
    print('  python parameters.py wf.json workflow.params')
    print('  python parameters.py wf.json "agent:text=Hello world" --output custom.json')


def main():
    """Função principal."""
    parser = argparse.ArgumentParser(
        description='Configura parâmetros de workflows N8N baseado em fórmulas de texto',
        add_help=False
    )
    parser.add_argument('workflow', help='Arquivo JSON do workflow')
    parser.add_argument('formula', help='Fórmula ou arquivo .params')
    parser.add_argument('--output', '-o', help='Arquivo de saída')
    parser.add_argument('--validate', '-v', action='store_true',
                       help='Apenas valida, não aplica')
    parser.add_argument('--help', '-h', action='store_true',
                       help='Mostra ajuda')
    parser.add_argument('--one', '-one', action='store_true',
                       help='Imprime apenas o nome do arquivo gerado')

    args = parser.parse_args()

    if args.help:
        print_usage()
        sys.exit(0)

    workflow_path = args.workflow
    formula_input = args.formula

    # Verifica se workflow existe
    if not Path(workflow_path).exists():
        print(f"ERRO: Arquivo não encontrado: {workflow_path}")
        sys.exit(1)

    # Determina se é arquivo ou fórmula direta
    if formula_input.endswith('.params'):
        if not Path(formula_input).exists():
            if not args.one:
                print(f"ERRO: Arquivo não encontrado: {formula_input}")
            sys.exit(1)
        formula = ParametersCreate.ler_params(formula_input)
        if not args.one:
            print(f"Parâmetros lidos de: {formula_input}")
    else:
        formula = formula_input

    if not args.one:
        print(f"Fórmula: {formula}")
        print()

    try:
        config = ParametersCreate(workflow_path)

        # Valida parâmetros
        if not config.validar_parametros(formula):
            sys.exit(1)

        if args.validate:
            if not args.one:
                print("\nValidação: OK - Todos os nodes e campos são válidos")
            sys.exit(0)

        # Aplica parâmetros
        config.aplicar_parametros(formula, silent=args.one)
        config.salvar(args.output, silent=args.one, one_mode=args.one)

    except json.JSONDecodeError as e:
        if not args.one:
            print(f"ERRO: JSON inválido em {workflow_path}")
            print(f"  {e}")
        sys.exit(1)
    except Exception as e:
        if not args.one:
            print(f"ERRO: {e}")
            import traceback
            traceback.print_exc()
        sys.exit(1)


if __name__ == "__main__":
    # Se não há argumentos suficientes, mostra ajuda
    if len(sys.argv) < 2:
        print_usage()
        sys.exit(1)
    main()

