# ============================================================
# ALIASES DE NOMES CURTOS
# ============================================================
# Mapeamento de nome curto -> nome completo do tipo
# Use sempre o nome curto (ex: 'set', 'agent', 'httpRequest')
ALIASES = {}

for full_type, info in CATALOGO_NODES.items():
    # Extrair o nome curto (após o último ponto)
    short_name = full_type.split('.')[-1]
    # Se já existe, verificar conflito e priorizar
    if short_name not in ALIASES:
        ALIASES[short_name] = full_type


def resolve_node_type(node_type):
    """
    Resolve um tipo de node usando nome curto.

    Args:
        node_type: Nome curto (ex: 'merge', 'agent', 'httpRequest')
                   Nomes longos não são suportados

    Returns:
        O nome completo do node para N8N ou None se não encontrado
    """
    # Tentar resolver pelo alias (nome curto)
    if node_type in ALIASES:
        return ALIASES[node_type]

    # Tentar busca parcial case-insensitive
    node_type_lower = node_type.lower()
    for short_name, full_type in ALIASES.items():
        if short_name.lower() == node_type_lower:
            return full_type

    return None


def get_connection_type(node_type):
    """Retorna o tipo de conexão padrão para um node"""
    resolved_type = resolve_node_type(node_type)
    if resolved_type and resolved_type in CATALOGO_NODES:
        return CATALOGO_NODES[resolved_type].get("connectionType", "main")
    return "main"


def exportar_catalogo():
    """Exporta o catálogo para um arquivo JSON"""
    with open('catalogo_nodes.json', 'w', encoding='utf-8') as f:
        json.dump(CATALOGO_NODES, f, indent=2, ensure_ascii=False)
    print("Catálogo exportado para catalogo_nodes.json")


if __name__ == "__main__":
    print("=== Catálogo de Nós N8N ===")
    print(f"Total de nodes disponíveis: {len(CATALOGO_NODES)}")
    print("\nNodes disponíveis:")
    for node_key in sorted(CATALOGO_NODES.keys()):
        info = CATALOGO_NODES[node_key]
        conn_type = info.get("connectionType", "main")
        print(f"  - {node_key} ({info['name']}) [{conn_type}]")

    print("\nExportando catálogo...")
    exportar_catalogo()

